final:
module top_module(
    input clk,
    input reset,
    input data_in,
    input shift_en,
    output reg data_out
);reg [7:0] clear_reg;

    always @(posedge clk) begin
        if (reset) begin
            clear_reg <= 8'b0;
        end else if (shift_en) begin
            clear_reg <= {clear_reg[6:0], data_in};
        end
    end

    assign data_out = clear_reg[7];

endmodule
